// shadcn
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger
} from "@/components/ui/accordion";
import { Button } from "@/components/ui/button";

// constants
const faqs = [
  {
    question:
      "How Long Will It Take For My Order To Arrive After I Make Payment?",
    answer:
      "Because you are important to us, we want to know what you think about the products. As an added value, every time you rate the products you earn points."
  },
  {
    question: "How Can I Change My Shipping Address?",
    answer:
      "You can change your shipping address by logging into your account and visiting the address book section in your profile settings."
  },
  {
    question: "How Can I Track My Orders & Payment?",
    answer:
      "Once your order is shipped, you will receive a tracking number via email which you can use to track your package on our carrier's website."
  }
];

//  ------------------------------ | FAQ - 8 | ------------------------------  //

export default function Faq8() {
  return (
    <section className="py-20 md:py-28">
      <div className="container mx-auto px-4">
        <div className="grid grid-cols-12 gap-6">
          {/* Left Column: Heading & Button */}
          <div className="col-span-12 md:col-span-5 max-w-xs">
            <h2 className="mb-6">Frequently Asked Questions</h2>
            <p className="text-muted-foreground mb-8">
              This is a big one and i consider it one of the most important
              things for a designer to get right.
            </p>
            <Button size="lg" className="bg-primary hover:bg-primary/90">
              Get Started
            </Button>
          </div>

          {/* Right Column: Accordion */}
          <div className="col-span-12 md:col-span-7">
            <Accordion className="space-y-4">
              {faqs.map((item, index) => (
                <AccordionItem
                  key={index}
                  value={`item-${index}`}
                  className="rounded-2xl border border-muted bg-card px-6 py-2 shadow-sm"
                >
                  <AccordionTrigger>
                    <span className="text-left text-md sm:text-lg font-semibold">
                      {item.question}
                    </span>
                  </AccordionTrigger>
                  <AccordionContent className="text-muted-foreground pb-6">
                    {item.answer}
                  </AccordionContent>
                </AccordionItem>
              ))}
            </Accordion>
          </div>
        </div>
      </div>
    </section>
  );
}
